SELECT DISTINCT year, sport, event_gender, event_name, count(*) AS N 
FROM medals
WHERE season = 'Winter'
GROUP BY ALL
ORDER BY year DESC, sport, event_gender, event_name;

SELECT DISTINCT year FROM medals where season = 'Winter' ORDER BY year;
